// ── Step 1: Extract payload from webhook ──────────────────
const body = $input.first().json.body || $input.first().json;

const query = body.query || '';
const sessionId = body.sessionId || 'default';
const documentId = body.documentId || null;
const history = body.history || [];

if (!query) throw new Error('query is required');

// ── Step 2: Classify intent via simple keyword matching ───
let intent = 'answer';
const q = query.toLowerCase();
if (/\b(summarize|summarise|summary|tldr|overview)\b/.test(q)) intent = 'summarise';
else if (/\b(extract|pull out|list all|find all|get all)\b/.test(q)) intent = 'extract';
else if (/\b(send|email|notify|save|store|create|schedule)\b/.test(q)) intent = 'action';

return [{ json: { query, sessionId, documentId, history, intent } }];

