// Parse Gemini response and normalise output
const raw = $input.first().json;

// Gemini response structure: candidates[0].content.parts[0].text
const text = raw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let parsed;
try {
  // Strip markdown code fences if present (safety net)
  const clean = text.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { intent: 'answer', answer: text, confidence: 0.8 };
}

return [{ json: {
  answer: parsed.answer || 'I was unable to generate an answer.',
  intent: parsed.intent || 'answer',
  keyPoints: parsed.keyPoints || [],
  extractedData: parsed.extractedData || {},
  confidence: parsed.confidence || 0.9,
  suggestedActions: parsed.suggestedActions || [],
  actions: [],
  source: 'n8n-gemini'
}}];

