// Parse Gemini action response
const raw = $input.first().json;
const text = raw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let action;
try {
  const clean = text.replace(/```json|```/g, '').trim();
  action = JSON.parse(clean);
} catch(e) {
  action = { action_type: 'save' };
}

return [{ json: {
  answer: `Action queued: ${action.action_type}. ${action.body || ''}`,
  intent: 'action',
  keyPoints: [],
  extractedData: {},
  confidence: 0.85,
  actions: [action],
  source: 'n8n-gemini-action'
}}];

// Save result to a JSON log file
const fs = require('fs');
const logFile = '/tmp/ai-assistant-results.json';

let existing = [];
try {
  existing = JSON.parse(fs.readFileSync(logFile, 'utf8'));
} catch(e) {}

existing.push({
  timestamp: new Date().toISOString(),
  ...$json
});

fs.writeFileSync(logFile, JSON.stringify(existing.slice(-100), null, 2));

return [{ json: { ...$json, savedToLog: true } }];

// Merge all branches and build final response
const data = $input.first().json;
return [{ json: {
  answer: data.answer,
  intent: data.intent,
  keyPoints: data.keyPoints || [],
  extractedData: data.extractedData || {},
  confidence: data.confidence || 0.9,
  actions: data.actions || [],
  source: data.source || 'n8n-gemini',
  processedAt: new Date().toISOString()
}}];
